func TestNovelWatchDriftSummaryReportsThresholdBreach(t *testing.T) {
	current := scoredKeyword{Keyword: "ceramic mug", Score: 72}
	history := []scoredKeywordSnapshot{
		{scoredKeyword: scoredKeyword{Keyword: "ceramic mug", Score: 52}},
		{scoredKeyword: current},
	}
	got := driftSummary(history, current, 10)
	if got["status"] != "drift" {
		t.Fatalf("status = %v, want drift", got["status"])
	}
	if got["score_change"] != 20.0 {
		t.Fatalf("score_change = %v, want 20", got["score_change"])
	}
}
